function resetImageControls() {
    if (!window.connectedDevice || !window.connectedDevice.ip) {
        console.warn('[IMAGE] No device connected');
        return;
    }
    
    // 弹出确认对话框
    if (!confirm('确认重置画面控制到系统默认值？')) {
        return;
    }
    
    var dev = window.connectedDevice.ip;
    console.log('[IMAGE] Resetting image controls to defaults...');
    
    // 系统默认值
    var defaults = {
        brightness: 50,
        contrast: 50,
        saturation: 50,
        sharpness: 50,
        wbRed: 100,
        wbBlue: 100,
        dnrSpatial: 50,
        dnrTemporal: 50,
        exposureMode: 'auto',
        shutterSpeed: '1/100',
        irisLevel: 1600
    };
    
