    document.getElementById('brightnessVal').textContent = defaults.brightness;
    document.getElementById('consoleContrast').value = defaults.contrast;
    document.getElementById('contrastVal').textContent = defaults.contrast;
    document.getElementById('consoleSaturation').value = defaults.saturation;
    document.getElementById('saturationVal').textContent = defaults.saturation;
    document.getElementById('consoleSharpness').value = defaults.sharpness;
    document.getElementById('sharpnessVal').textContent = defaults.sharpness;
    document.getElementById('wbRed').value = defaults.wbRed;
    document.getElementById('wbRedVal').textContent = defaults.wbRed;
    document.getElementById('wbBlue').value = defaults.wbBlue;
    document.getElementById('wbBlueVal').textContent = defaults.wbBlue;
    document.getElementById('dnrSpatial').value = defaults.dnrSpatial;
    document.getElementById('dnrSpatialVal').textContent = defaults.dnrSpatial;
    document.getElementById('dnrTemporal').value = defaults.dnrTemporal;
    document.getElementById('dnrTemporalVal').textContent = defaults.dnrTemporal;
    document.getElementById('exposureMode').value = defaults.exposureMode;
    document.getElementById('shutterSpeed').value = defaults.shutterSpeed;
    document.getElementById('irisLevel').value = defaults.irisLevel;
    
    // 发送 API 请求重置设备
    apiPost('/api/v1/ptz/' + dev + '/image/reset', {})
        .then(function(r) {
            if (r && r.success) {
                showToast('success', '画面控制已重置到系统默认值');
            } else {
                showToast('error', '重置失败: ' + (r.message || '未知错误'));
