// v6.20 + v7.0: 禁用所有控制区域（PTZ + 媒体 + 跟踪 + 画面）
function disableImageControls(reason) {
    // v7.11: 禁用画面控制控件（包括增益）
    var controls = [
        'consoleBrightness', 'consoleContrast', 'consoleSaturation', 'consoleSharpness',
        'wbMode', 'wbRed', 'wbBlue', 'dnrSpatial', 'dnrTemporal',
        'exposureMode', 'shutterSpeed', 'irisLevel', 'gainLevel',  // v7.11: 添加 gainLevel
        'infoOsdSwitch', 'ptzOsdSwitch'
    ];
    controls.forEach(function(id) {
        var el = document.getElementById(id);
        if (el) {
            el.disabled = true;
            el.style.opacity = '0.5';
            el.style.cursor = 'not-allowed';
        }
    });
    
    // v7.0: 禁用 PTZ 控制按钮
    var ptzSection = document.getElementById('ptzControlSection');
    if (ptzSection) {
        var ptzBtns = ptzSection.querySelectorAll('.btn, .ptz-btn');
        ptzBtns.forEach(function(btn) {
            if (btn.id !== 'ptzSpeed') {
                btn.disabled = true;
                btn.style.opacity = '0.5';
                btn.style.cursor = 'not-allowed';
            }
        });
    }
    
    // v7.0: 禁用媒体操作按钮
    var mediaButtons = ['btnConsoleSnapshot', 'btnConsoleRecordStart', 'btnConsoleRecordStop', 'btnLiveStackStart', 'btnLiveStackStop', 'btnLiveStackSave'];
    mediaButtons.forEach(function(id) {
        var el = document.getElementById(id);
        if (el) {
            el.disabled = true;
            el.style.opacity = '0.5';
            el.style.cursor = 'not-allowed';
        }
    });
    
    // v7.0: 禁用跟踪控制按钮
    var trackButtons = ['btnTrackSidereal', 'btnTrackLunar', 'btnTrackSolar', 'btnTrackOff'];
    trackButtons.forEach(function(id) {
        var el = document.getElementById(id);
        if (el) {
            el.disabled = true;
            el.style.opacity = '0.5';
            el.style.cursor = 'not-allowed';
        }
    });
    
    // v7.01: 显示主控台提示框，移除画面控制区的提示
    var consoleWarning = document.getElementById('consoleWarning');
    if (consoleWarning) {
        consoleWarning.style.display = 'block';
    }
    
    // 移除画面控制区的旧提示（如果存在）
    var oldWarning = document.getElementById('functionCacheWarning');
    if (oldWarning) oldWarning.remove();
    
    // v7.0: 停止 PTZ 坐标刷新
    if (window.stopPtzImagePoll) window.stopPtzImagePoll();
}

